<template>
  <div class="container">
    <div class="row">
      <div class="col-md-12">
        <div class="mt-4 mb-4">
          <h1><strong class="courier">Scorebord</strong></h1>
        </div>
        <div class="card text-white text-left mb-5">
          <div class="maskot">
            <img src="~@/assets/img/maskot.png" class="maskot-img">
          </div>
          <div class="card-body">
            <!-- <button @click="urutkan" class="btn btn-danger text-white mt-5 mb-3">Urutkan</button> -->
            <div class="table-responsive pt-5">
              <table class="table table-striped text-white">
                <thead>
                  <tr>
                    <th>TIM</th>
                    <th>KELAS</th>
                    <th>WAKTU</th>
                    <th>CASE</th>
                  </tr>
                </thead>
                <tbody class="monaco">
                  <tr v-for="t in tim" :key="t.id">
                    <td>{{ t.nama }}</td>
                    <td>{{ t.kelas }}</td>
                    <td>{{ t.waktu }}</td>
                    <td>{{ t.case }}</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>

        <div class="card text-white text-left mb-5">
          <div class="card-body monaco">
            <form @submit.prevent="addTim">
            <div class="form-group">
              <input type="text" v-model="inputNama" class="form-control" placeholder="Nama Tim" required>
            </div>
            <div class="form-group">
              <select v-model="inputKelas" class="form-control" required>
                <option value=""># Kelas #</option>
                <option v-for="k in kelas" :key="k" :value="k">{{ k }}</option>
              </select>
            </div>
            <div class="form-group">
              <input type="text" v-model="inputWaktu" class="form-control" placeholder="Waktu" required>
            </div>
            <div class="form-group">
              <select v-model="inputCase" class="form-control" required>
                <option value=""># Case #</option>
                <option value="1">Case-1</option>
                <option value="2">Case-2</option>
              </select>
            </div>
            <button class="btn btn-green text-white">Simpan</button>
          </form>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
  export default {
    data() {
      return {
        inputNama: "",
        inputKelas: "",
        inputWaktu: "",
        inputCase: "",
        kelas: [
          'XII.RPL-1',
          'XII.RPL-2',
          'XII.RPL-3',
          'XII.RPL-4',
        ],
        tim: [
          {
            id: "",
            nama: "",
            kelas: "",
            waktu: "",
            case: "",
          }
        ]
      }
    },
    methods: {
      addTim() {
        let curr_id = this.tim.length;
        let currTim = {
          id: curr_id,
          nama: this.inputNama,
          kelas: this.inputKelas,
          waktu: this.inputWaktu,
          case: this.inputCase,
        }
        this.tim.push(currTim);
        this.inputNama = "";
        this.inputKelas = "";
        this.inputWaktu = "";
        this.inputCase = "";
      }
    }
  }
</script>

